  coaching_execution = '{"movement_description":"Move from bear to crab and back through a controlled hip turn without collapsing shoulders or rushing.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Move from bear to crab and back through a controlled hip turn without collapsing shoulders or rushing.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Bear-to-Crab Switch from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"breathing_cues":["Exhale without crunching.","Use a brace you can breathe through.","Reset if breath-holding becomes the strategy."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."],"quality_gate":["Athlete can breathe while maintaining the target shape.","Left and right sides look similar enough for the intended level.","No pain, pinching, dizziness, or uncontrolled pressure symptoms.","Reps remain repeatable without coach constantly rescuing the position."],"stop_signs":["Back pain, neck symptoms, dizziness, or sharp joint pain.","Visible rib flare, lumbar sag, or pelvic shift that cannot be corrected.","Athlete cannot continue breathing behind the brace.","The drill turns into a conditioning challenge instead of control practice."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Crawling patterns","Loaded carries","Tumbling skill practice","Strength work requiring trunk stiffness"],"pairs_well_after":["90/90 Breathing with Reach","Dead Bug Heel Tap","Bird Dog ISO Hold","Bear Plank Hold"],"good_for_sessions":["general_warmup","crawling_prep","squat_prep","overhead_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete cannot breathe while bracing.","Low-back, neck, shoulder, wrist, hip, or knee pain appears in the setup.","The coach needs a true high-output speed, jump, or throw block and this drill would create fatigue first.","The athlete is using momentum or fatigue tolerance instead of position control."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Vortex Exercise Card Authoring Guide: Core & Body Control primary homes and resilience/movement-intelligence sequencing","NSCA-style trunk stability and resistance training technique principles","Gymnastics/body-shape progression principles for hollow, arch, rolling, and hand-support skills"],"internal_notes":["Film Bear-to-Crab Switch from front and side when possible to see rib, pelvis, shoulder, and hip control.","Do not program as HIIT or a burnout finisher.","Core & Body Control should score Body Control high; Strength is secondary unless load/lever/tension is the main adaptation."]}'::jsonb,
  updated_at = now()
WHERE slug = 'bear-to-crab-switch';

