-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for quality-first trunk and body control.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('90-90-breathing-with-reach', '90/90 Breathing with Reach creates a clear core-and-body-control problem: the limbs, support base, or external cue changes while the athlete must keep ribs, pelvis, shoulders, and hips organized. That teaches force transfer and position ownership without relying on fatigue, chaos, or heavy external loading.', 'Belongs in Prepare & Access because it builds low-fatigue access to breathing, rib-pelvis stacking, and trunk activation before higher-intent work. It should increase readiness without stealing output.', 'Use early in Prepare & Access as a low-fatigue breathing, bracing, or activation drill before trunk work, crawling, tumbling, sprinting, or lifting.', 'Do not chase reps, time, burn, or complexity after position quality breaks. The card loses value when athletes hold breath, flare ribs, arch the low back, rotate unintentionally, or turn it into conditioning.', 'Scale by lever length, support, range of motion, tempo, load, breathing demand, and total volume. The athlete should finish with the same alignment and breathing quality they started with.'),
  ('crocodile-breathing', 'Crocodile Breathing creates a clear core-and-body-control problem: the limbs, support base, or external cue changes while the athlete must keep ribs, pelvis, shoulders, and hips organized. That teaches force transfer and position ownership without relying on fatigue, chaos, or heavy external loading.', 'Belongs in Prepare & Access because it builds low-fatigue access to breathing, rib-pelvis stacking, and trunk activation before higher-intent work. It should increase readiness without stealing output.', 'Use early in Prepare & Access as a low-fatigue breathing, bracing, or activation drill before trunk work, crawling, tumbling, sprinting, or lifting.', 'Do not chase reps, time, burn, or complexity after position quality breaks. The card loses value when athletes hold breath, flare ribs, arch the low back, rotate unintentionally, or turn it into conditioning.', 'Scale by lever length, support, range of motion, tempo, load, breathing demand, and total volume. The athlete should finish with the same alignment and breathing quality they started with.'),
  ('supine-hook-lying-brace-with-exhale', 'Supine Hook-Lying Brace with Exhale creates a clear core-and-body-control problem: the limbs, support base, or external cue changes while the athlete must keep ribs, pelvis, shoulders, and hips organized. That teaches force transfer and position ownership without relying on fatigue, chaos, or heavy external loading.', 'Belongs in Prepare & Access because it builds low-fatigue access to breathing, rib-pelvis stacking, and trunk activation before higher-intent work. It should increase readiness without stealing output.', 'Use early in Prepare & Access as a low-fatigue breathing, bracing, or activation drill before trunk work, crawling, tumbling, sprinting, or lifting.', 'Do not chase reps, time, burn, or complexity after position quality breaks. The card loses value when athletes hold breath, flare ribs, arch the low back, rotate unintentionally, or turn it into conditioning.', 'Scale by lever length, support, range of motion, tempo, load, breathing demand, and total volume. The athlete should finish with the same alignment and breathing quality they started with.'),
  ('dead-bug-heel-tap', 'Dead Bug Heel Tap creates a clear core-and-body-control problem: the limbs, support base, or external cue changes while the athlete must keep ribs, pelvis, shoulders, and hips organized. That teaches force transfer and position ownership without relying on fatigue, chaos, or heavy external loading.', 'Belongs in Resilience because the main adaptation is trunk/pelvis anti-movement control, joint ownership, and tissue-tolerant stability. It is not a speed, max-power, or HIIT exposure.', 'Use in Resilience after Output and Capacity, or earlier as a very low-intensity activation option when it will not steal speed, power, or skill quality.', 'Do not chase reps, time, burn, or complexity after position quality breaks. The card loses value when athletes hold breath, flare ribs, arch the low back, rotate unintentionally, or turn it into conditioning.', 'Scale by lever length, support, range of motion, tempo, load, breathing demand, and total volume. The athlete should finish with the same alignment and breathing quality they started with.'),
