-- Core & Body Control cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'core_body_control_readiness',
  NULL,
  'Core & Body Control without conditioning drift or wrong phase intent',
  'Trunk, pelvis, shape, crawling, and anti-movement control drills must stay quality-first — low-fatigue in Prepare & Access, controlled in Resilience and Movement Intelligence, and never disguised HIIT or burnout finishers.',
  'Core & Body Control cards span breathing resets, anti-extension/rotation holds, hollow/arch shapes, crawling transitions, loaded pallof patterns, and inversion prep for athletes who need rib-pelvis organization and force transfer without fatigue-chasing.',
  'Body control underpins sprinting, tumbling, lifting, and COD. Poor placement, breath-holding, or complexity before position ownership trains compensations and steals from Output work.',
  'Use Prepare & Access cards as low-fatigue breathing and activation primers. Place Resilience anti-movement work after Output when tissue tolerance is the goal. Keep Movement Intelligence shape and roll drills submaximal until hollow/arch ownership is clean.',
  'Do not chase reps, time, or burn after position leaks; do not program core circuits before fresh speed/jump blocks; do not tag fatigue challenges as body control when the athlete is breath-holding or arching.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
